class Solution:
    def findOrder(self, numCourses: int, prerequisites: List[List[int]]) -> List[int]:
        graph = [[] for _ in range(numCourses)]
        visited = [0] * numCourses
        order = []
        for x, y in prerequisites:
            graph[y].append(x)
        def dfs(i):
            if visited[i] == -1:
                return False
            if visited[i] == 1:
                return True
            visited[i] = -1
            for j in graph[i]:
                if not dfs(j):
                    return False
            visited[i] = 1
            order.append(i)
            return True
        for i in range(numCourses):
            if not dfs(i):
                return []
        return order[::-1]
